  this.turn = function(cell) {
    // Simple strategy: look for gold first, then navigate toward it
    // If gold is adjacent and reachable, move toward it
    // Otherwise, collect blocks and build stairs as needed

    // Check if gold is visible in adjacent cells
    if (cell.left.type === 3 && Math.abs(cell.left.level - cell.level) <= 1) {
      return "left";
    }
    if (cell.up.type === 3 && Math.abs(cell.up.level - cell.level) <= 1) {
      return "up";
    }
    if (cell.right.type === 3 && Math.abs(cell.right.level - cell.level) <= 1) {
      return "right";
    }
    if (cell.down.type === 3 && Math.abs(cell.down.level - cell.level) <= 1) {
      return "down";
    }

    // If we're on gold, we need to be at the right level (but this shouldn't happen normally)
    if (cell.type === 3) {
      return "pickup"; // Just do something
    }

    // Look for blocks to collect
    if (cell.left.type === 2 && cell.left.level > 0) {
      return "left";
    }
    if (cell.up.type === 2 && cell.up.level > 0) {
      return "up";
    }
    if (cell.right.type === 2 && cell.right.level > 0) {
      return "right";
    }
    if (cell.down.type === 2 && cell.down.level > 0) {
      return "down";
    }

    // Try to move to a higher elevation if possible
    if (cell.left.type === 0 && cell.left.level === cell.level + 1) {
      return "left";
    }
    if (cell.up.type === 0 && cell.up.level === cell.level + 1) {
      return "up";
    }
    if (cell.right.type === 0 && cell.right.level === cell.level + 1) {
      return "right";
    }
    if (cell.down.type === 0 && cell.down.level === cell.level + 1) {
      return "down";
    }

    // Try to move to same level or lower
    var directions = ["left", "up", "right", "down"];
    for (var i = 0; i < directions.length; i++) {
      var dir = directions[i];
      if (cell[dir].type === 0 && Math.abs(cell[dir].level - cell.level) <= 1) {
        return dir;
      }
    }

    // If stuck, try pickup or drop
    return Math.random() < 0.5 ? "pickup" : "drop";
  };
}
