  this.markVisited = function(cell, direction) {
    var key = cell.level + "_" + direction;
    this.visited[key] = (this.visited[key] || 0) + 1;
  };

  this.canMove = function(cell, direction) {
    var target = cell[direction];
    return target.type === 0 && Math.abs(target.level - cell.level) <= 1;
  };

  this.canPickup = function(cell, direction) {
    var target = cell[direction];
    return target.type === 2 && target.level > 0;
  };

  this.canReachGold = function(cell, direction) {
    var target = cell[direction];
    return target.type === 3 && Math.abs(target.level - cell.level) <= 1;
