    // Second priority: collect blocks
    for (var i = 0; i < this.directions.length; i++) {
      var dir = this.directions[i];
      if (this.canPickup(cell, dir)) {
        return dir;
      }
    }

    // Third priority: move to higher ground if possible
    for (var i = 0; i < this.directions.length; i++) {
      var dir = this.directions[i];
      if (this.canMove(cell, dir) && cell[dir].level > cell.level) {
